function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return null;
}

function normalizeSource(value) {
  const source = String(value || '').toLowerCase();
  if (['comment', 'comments', 'post_comment', 'comentario', 'comentarios'].includes(source)) return 'post_comment';
  if (['new_follower', 'follower', 'follow', 'seguidor', 'novo_seguidor'].includes(source)) return 'new_follower';
  return 'story_reply';
}

function classifyPotential(text) {
  const value = String(text || '').toLowerCase();
  if (/(valor|preco|matricula|inscricao|link|comprar|agenda|consulta|palestra|orcamento)/.test(value)) return 'alto';
  if (/(curso|formacao|aasi|aura|imersao|zumbido|interesse|quero|como funciona)/.test(value)) return 'medio';
  if (value.trim()) return 'baixo';
  return 'nao_classificado';
}

function pushRow(rows, row, rawPayload) {
  const messageText = firstValue(row.message_text, row.text, row.message, row.comment_text, row.caption, '');
  const source = normalizeSource(row.source || row.field || row.type);
  rows.push({
    tenant_name: firstValue(row.tenant_name, $env.PLATAFORMA_TENANT_NAME, 'Juliana Coutinho'),
    account_name: firstValue(row.account_name, $env.INSTAGRAM_ACCOUNT_NAME, 'Juliana Coutinho'),
    username: firstValue(row.username, $env.INSTAGRAM_USERNAME, 'fga.jucoutinho'),
    source,
    marketing_type: 'interacao_marketing',
    external_id: firstValue(row.external_id, row.id, row.mid, row.comment_id, row.follower_id),
    profile_username: firstValue(row.profile_username, row.username_from, row.from_username, row.sender_username, row.sender?.username, row.from?.username),
    profile_name: firstValue(row.profile_name, row.name_from, row.from_name, row.sender_name, row.sender?.name, row.from?.name),
    message_text: messageText,
    media_id: firstValue(row.media_id, row.post_id, row.story_id),
    post_id: firstValue(row.post_id, row.media_id),
    post_permalink: firstValue(row.post_permalink, row.permalink),
    interaction_at: firstValue(row.interaction_at, row.timestamp, row.created_time, row.time, new Date().toISOString()),
    status: firstValue(row.status, 'novo'),
    potential: firstValue(row.potential, classifyPotential(messageText)),
    product_topic: firstValue(row.product_topic, null),
    next_action: firstValue(row.next_action, null),
    origem: 'n8n_instagram_directs',
    raw_payload: rawPayload || row
  });
}

const rows = [];

for (const item of items) {
  const body = item.json.body || item.json;

  if (Array.isArray(body)) {
    for (const entry of body) pushRow(rows, entry, entry);
    continue;
  }

  if (Array.isArray(body.rows)) {
    for (const row of body.rows) pushRow(rows, row, row);
    continue;
  }

  if (Array.isArray(body.entry)) {
    for (const entry of body.entry) {
      if (Array.isArray(entry.messaging)) {
        for (const message of entry.messaging) {
          pushRow(rows, {
            source: 'story_reply',
            external_id: firstValue(message.message?.mid, message.id),
            profile_username: firstValue(message.sender?.username, message.sender?.id),
            profile_name: firstValue(message.sender?.name),
            message_text: firstValue(message.message?.text, message.postback?.title),
            media_id: firstValue(message.message?.reply_to?.mid, message.referral?.media_id),
            post_permalink: firstValue(message.referral?.ref),
            interaction_at: message.timestamp ? new Date(Number(message.timestamp)).toISOString() : new Date().toISOString()
          }, message);
        }
      }

      if (Array.isArray(entry.changes)) {
        for (const change of entry.changes) {
          const value = change.value || {};
          const field = change.field || value.item || value.verb;
          const source = String(field || '').toLowerCase().includes('follow') ? 'new_follower' : 'post_comment';
          pushRow(rows, {
            source,
            external_id: firstValue(value.comment_id, value.id, value.from?.id),
            profile_username: firstValue(value.from?.username, value.from?.id),
            profile_name: firstValue(value.from?.name),
            message_text: firstValue(value.message, value.text, source === 'new_follower' ? 'Novo seguidor' : ''),
            media_id: firstValue(value.media_id, value.post_id),
            post_id: firstValue(value.post_id, value.media_id),
            post_permalink: firstValue(value.permalink),
            interaction_at: firstValue(value.created_time, value.timestamp, new Date().toISOString())
          }, change);
        }
      }
    }
    continue;
  }

  pushRow(rows, body, body);
}

if (!rows.length) {
  return [{ json: { skipped: true, reason: 'Nenhuma interacao de marketing encontrada no payload.' } }];
}

return rows.map((row) => ({ json: row }));
